spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var totalDots = 12;
    var numGroups = 3;
    var dotsPerGroup = 4;
    var dotRadius = 10;

    // Positions
    var startX = W / 2;
    var startY = H / 4 + 10;

    var boxWidth = W * 0.22;
    var boxHeight = 70;
    var boxCenters = [
      { x: W * 0.22, y: H * 0.7 },
      { x: W * 0.5, y: H * 0.7 },
      { x: W * 0.78, y: H * 0.7 }
    ];

    var dotOffsets = [
      { x: -20, y: -15 },
      { x: 20, y: -15 },
      { x: -20, y: 15 },
      { x: 20, y: 15 }
    ];

    // Animation timing (6s cycle)
    var duration = 6000;
    var progress = (t % duration) / duration;

    // Draw destination boxes
    ctx.lineWidth = 2.5;
    for (var g = 0; g < numGroups; g++) {
      var box = boxCenters[g];
      ctx.strokeStyle = '#4B5563';
      if (progress > 0.6) {
        ctx.strokeStyle = '#3B82F6'; // Highlight when sharing is complete
      }
      ctx.beginPath();
      ctx.roundRect(box.x - boxWidth / 2, box.y - boxHeight / 2, boxWidth, boxHeight, 12);
      ctx.stroke();

      // Label
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.textAlign = 'center';
      ctx.fillText('Group ' + (g + 1), box.x, box.y - boxHeight / 2 - 8);
    }

    // Draw/Animate dots
    for (var i = 0; i < totalDots; i++) {
      var groupIdx = Math.floor(i / dotsPerGroup);
      var offsetIdx = i % dotsPerGroup;

      var destX = boxCenters[groupIdx].x + dotOffsets[offsetIdx].x;
      var destY = boxCenters[groupIdx].y + dotOffsets[offsetIdx].y;

      // Staggered slide progress
      var startDelay = 0.15 + i * 0.03;
      var slideProgress = Math.max(0, Math.min(1, (progress - startDelay) / 0.35));

      // Apply easeInOutQuad to slide
      var easeT = slideProgress < 0.5 ? 2 * slideProgress * slideProgress : 1 - Math.pow(-2 * slideProgress + 2, 2) / 2;

      var curX = startX + (destX - startX) * easeT;
      var curY = startY + (destY - startY) * easeT;

      // Stagger source layout in center before sliding
      if (slideProgress <= 0) {
        var col = i % 4;
        var row = Math.floor(i / 4);
        curX = startX - 45 + col * 30;
        curY = startY - 15 + row * 25;
      }

      ctx.fillStyle = slideProgress > 0.8 ? '#10B981' : '#FBBF24';
      ctx.beginPath();
      ctx.arc(curX, curY, dotRadius, 0, Math.PI * 2);
      ctx.fill();
    }

    // Top Title / Stage explanation
    ctx.fillStyle = '#F3F4F6';
    ctx.font = 'bold 16px -apple-system, sans-serif';
    ctx.textAlign = 'center';

    if (progress < 0.15) {
      ctx.fillText('12 Items to divide into 3 groups', W / 2, 40);
    } else if (progress < 0.6) {
      ctx.fillText('Distributing items equally...', W / 2, 40);
    } else {
      ctx.fillText('12 ÷ 3 = 4 items in each group', W / 2, 40);
    }
  }
};
